    37→  // requires only the callbacks, but passes both for consistency.
    38→  HttpPendingStream(Envoy::ConnectionPool::ConnPoolImplBase& parent, Http::ResponseDecoder& decoder,
    39→                    Http::ConnectionPool::Callbacks& callbacks, bool can_send_early_data)
    40→      : Envoy::ConnectionPool::PendingStream(parent, can_send_early_data),
    41→        context_(&decoder, &callbacks) {}
