   169→/* An implementation of Envoy::ConnectionPool::ConnPoolImplBase for HTTP/1 and HTTP/2
   170→ */
   171→class FixedHttpConnPoolImpl : public HttpConnPoolImplBase {
   172→public:
   173→  using CreateClientFn =
   174→      std::function<Envoy::ConnectionPool::ActiveClientPtr(HttpConnPoolImplBase* pool)>;
   175→  using CreateCodecFn = std::function<CodecClientPtr(Upstream::Host::CreateConnectionData& data,
   176→                                                     HttpConnPoolImplBase* pool)>;
   177→
   178→  FixedHttpConnPoolImpl(
   179→      Upstream::HostConstSharedPtr host, Upstream::ResourcePriority priority,
   180→      Event::Dispatcher& dispatcher, const Network::ConnectionSocket::OptionsSharedPtr& options,
   181→      const Network::TransportSocketOptionsConstSharedPtr& transport_socket_options,
   182→      Random::RandomGenerator& random_generator, Upstream::ClusterConnectivityState& state,
   183→      CreateClientFn client_fn, CreateCodecFn codec_fn, std::vector<Http::Protocol> protocols,
   184→      Server::OverloadManager& overload_manager,
   185→      absl::optional<Http::HttpServerPropertiesCache::Origin> origin = absl::nullopt,
   186→      Http::HttpServerPropertiesCacheSharedPtr cache = nullptr)
   187→      : HttpConnPoolImplBase(host, priority, dispatcher, options, transport_socket_options,
   188→                             random_generator, state, protocols, overload_manager),
   189→        codec_fn_(codec_fn), client_fn_(client_fn), protocol_(protocols[0]), cache_(cache) {
   190→    setOrigin(origin);
   191→    ASSERT(protocols.size() == 1);
   192→  }
   193→
   194→  CodecClientPtr createCodecClient(Upstream::Host::CreateConnectionData& data) override {
   195→    return codec_fn_(data, this);
   196→  }
   197→
   198→  Envoy::ConnectionPool::ActiveClientPtr instantiateActiveClient() override {
   199→    return client_fn_(this);
   200→  }
   201→
   202→  absl::string_view protocolDescription() const override {
   203→    return Utility::getProtocolString(protocol_);
   204→  }
   205→
   206→  Http::HttpServerPropertiesCacheSharedPtr cache() override { return cache_; }
   207→
   208→protected:
   209→  const CreateCodecFn codec_fn_;
   210→  const CreateClientFn client_fn_;
   211→  const Http::Protocol protocol_;
   212→
   213→  Http::HttpServerPropertiesCacheSharedPtr cache_;
   214→};
