   278→void ConnPoolImplBase::onStreamClosed(Envoy::ConnectionPool::ActiveClient& client,
   279→                                      bool delay_attaching_stream) {
   280→  ENVOY_CONN_LOG(
   281→      debug, "destroying stream: {} active remaining, readyForStream {}, currentUnusedCapacity {}",
   282→      client, client.numActiveStreams(), client.readyForStream(), client.currentUnusedCapacity());
   283→  ASSERT(num_active_streams_ > 0, dumpState());
   284→  cluster_connectivity_state_.decrActiveStreams(1);
   285→  num_active_streams_--;
   286→  host_->stats().rq_active_.dec();
   287→  host_->cluster().trafficStats()->upstream_rq_active_.dec();
   288→  host_->cluster().resourceManager(priority_).requests().dec();
   289→  // We don't update the capacity for HTTP/3 as the stream count should only
   290→  // increase when a MAX_STREAMS frame is received.
   291→  if (trackStreamCapacity()) {
   292→    // If the effective client capacity was limited by concurrency, increase connected capacity.
   293→    bool limited_by_concurrency =
   294→        client.remaining_streams_ > client.concurrent_stream_limit_ - client.numActiveStreams() - 1;
   295→    // The capacity calculated by concurrency could be negative if a SETTINGS frame lowered the
   296→    // number of allowed streams. In this case, connecting_and_connected_stream_capacity_ can be
   297→    // negative, and effective client capacity was still limited by concurrency. Compare
   298→    // client.concurrent_stream_limit_ and client.numActiveStreams() directly to avoid overflow.
   299→    bool negative_capacity = client.concurrent_stream_limit_ < client.numActiveStreams() + 1;
   300→    if (negative_capacity || limited_by_concurrency) {
   301→      incrConnectingAndConnectedStreamCapacity(1, client);
   302→    }
   303→  }
   304→  if (client.state() == ActiveClient::State::Draining && client.numActiveStreams() == 0) {
   305→    // Close out the draining client if we no longer have active streams.
   306→    client.close();
